import React from 'react'
import { Card, CardActionArea, CardContent, CardHeader, CardMedia, Divider, Typography } from '@material-ui/core'
import { makeStyles } from '@material-ui/styles'
import { Link } from 'react-router-dom'

const useStyle = makeStyles(theme => {
  return {
    root: {
      '& .MuiCardActionArea-focusHighlight': {
        background: 'none'
      }
    },
    avatar: {
      background: '#162276',
      width: theme.spacing(7),
      height: theme.spacing(7),
    },
    media: {
      height: 0,
      paddingTop: '56.25%'
    },

    cardLink: {
      textDecoration: 'none',
      color: 'inherit'
    }
  }
})


export default function ClassroomCards({ subjects }) {
  const classes = useStyle()


  return (
    <>
      <Card className={classes.root}>
        <Link
          className={classes.cardLink}
          to={{
            pathname: '/teacherFeed',
            search: `?${subject.subjectName}`
          }}>

          <CardActionArea>

            <CardMedia
              className={classes.media}
              // image={subject.imagebg}
            />
            <CardHeader
              title={subjects.subjectName}
              subheader={subjects.yearSection}
            />

            <Divider />

            <CardContent>
              <Typography>
                {/* {subject.body} */}
              </Typography>
            </CardContent>

          </CardActionArea>
        </Link>
      </Card>
    </>
  )
}
